55	    let body = serde_json::json!({"username": username, "password": password});
56	    let resp = Request::post("/auth/register")
57	        .header("Content-Type", "application/json")
58	        .body(body.to_string())
59	        .map_err(|e| ApiError { status: 0, code: "REQUEST".into(), message: format!("{:?}", e) })?
60	        .send()
61	        .await
62	        .map_err(|e| ApiError { status: 0, code: "NETWORK".into(), message: e.to_string() })?;
63	
64	    if !resp.ok() { return Err(parse_error(resp).await); }
65	    resp.json().await.map_err(|e| ApiError { status: 0, code: "PARSE".into(), message: e.to_string() })
66	}
