162	
163	pub async fn list_evidence(keyword: &str, tag: &str, from: &str, to: &str)
164	    -> Result<Vec<EvidenceResponse>, ApiError>
165	{
166	    let mut q: Vec<String> = Vec::new();
167	    if !keyword.is_empty() { q.push(format!("keyword={}", urlencode(keyword))); }
168	    if !tag.is_empty() { q.push(format!("tag={}", urlencode(tag))); }
169	    if !from.is_empty() { q.push(format!("from={}", urlencode(from))); }
170	    if !to.is_empty() { q.push(format!("to={}", urlencode(to))); }
171	    let path = if q.is_empty() { "/evidence".to_string() }
172	               else { format!("/evidence?{}", q.join("&")) };
173	    let resp = Request::get(&path).send().await
174	        .map_err(|e| ApiError { status: 0, code: "NETWORK".into(), message: e.to_string() })?;
175	    if !resp.ok() { return Err(parse_error(resp).await); }
176	    resp.json().await.map_err(|e| ApiError { status: 0, code: "PARSE".into(), message: e.to_string() })
177	}
178	
179	fn urlencode(s: &str) -> String {
180	    // Minimal percent-encoding for safe ASCII query values.
181	    let mut out = String::with_capacity(s.len());
182	    for c in s.chars() {
183	        if c.is_ascii_alphanumeric() || "-_.~".contains(c) {
184	            out.push(c);
185	        } else {
186	            for b in c.to_string().bytes() {
187	                out.push_str(&format!("%{:02X}", b));
188	            }
189	        }
190	    }
191	    out
192	}
