12	#[component]
13	pub fn DashboardPage(
14	    user: ReadSignal<Option<UserResponse>>,
15	    set_page: WriteSignal<Page>,
16	    set_user: WriteSignal<Option<UserResponse>>,
17	) -> impl IntoView {
18	    let (health, set_health) = create_signal(Option::<Result<String, String>>::None);
19	    let (delete_msg, set_delete_msg) = create_signal(Option::<String>::None);
20	
21	    spawn_local(async move {
22	        let result = client::check_health().await;
23	        set_health.set(Some(result));
24	    });
25	
26	    // Session-expiry check: periodically verify session by calling /auth/me
27	    {
28	        let set_page = set_page;
29	        let set_user = set_user;
30	        spawn_local(async move {
31	            gloo_timers::future::sleep(std::time::Duration::from_secs(60)).await;
32	            if client::get_me().await.is_err() {
33	                set_user.set(None);
34	                set_page.set(Page::Login);
35	            }
36	        });
37	    }
38	
39	    let request_delete = move |_| {
40	        spawn_local(async move {
41	            match client::request_account_deletion().await {
42	                Ok(v) => set_delete_msg.set(Some(
43	                    v.get("message").and_then(|m| m.as_str()).unwrap_or("Deletion requested").to_string(),
44	                )),
45	                Err(e) => set_delete_msg.set(Some(e.message)),
46	            }
47	        });
48	    };
49	
50	    let cancel_delete = move |_| {
51	        spawn_local(async move {
52	            match client::cancel_account_deletion().await {
53	                Ok(_) => set_delete_msg.set(Some("Deletion cancelled".into())),
54	                Err(e) => set_delete_msg.set(Some(e.message)),
55	            }
56	        });
57	    };
58	
59	    view! {
60	        <div class="app-body">
61	            <div class="card">
62	                <h2>"System Status"</h2>
63	                {move || match health.get() {
64	                    None => view! {
65	                        <span class="status-indicator status-loading">
66	                            <span class="dot dot-loading"></span>
67	                            "Checking..."
68	                        </span>
69	                    }.into_view(),
70	                    Some(Ok(s)) => view! {
71	                        <span class="status-indicator status-ok">
72	                            <span class="dot dot-ok"></span>
73	                            {format!("System: {}", s)}
74	                        </span>
75	                    }.into_view(),
76	                    Some(Err(e)) => view! {
77	                        <span class="status-indicator status-error">
78	                            <span class="dot dot-error"></span>
79	                            {format!("Error: {}", e)}
80	                        </span>
81	                    }.into_view(),
82	                }}
83	            </div>
84	
85	            <div class="card">
86	                <h2>"Profile"</h2>
87	                {move || user.get().map(|u| view! {
88	                    <div class="profile-info">
89	                        <p><strong>"Username: "</strong>{u.username.clone()}</p>
90	                        <p><strong>"Role: "</strong>{u.role.clone()}</p>
91	                    </div>
92	                })}
93	                <div class="account-lifecycle">
94	                    <h3>"Account Lifecycle"</h3>
95	                    <p class="muted">"Requesting deletion starts a 7-day cooling-off window. You can cancel anytime during that period."</p>
96	                    {move || delete_msg.get().map(|m| view! { <div class="msg msg-info">{m}</div> })}
97	                    <button class="btn btn-danger" on:click=request_delete>"Request Account Deletion"</button>
98	                    <button class="btn" on:click=cancel_delete>"Cancel Deletion"</button>
99	                </div>
100	            </div>
101	
102	            <WorkspacePage />
103	            <ReportsPage />
104	            <IntakePage />
105	            <EvidenceSearchPage />
106	            <AddressBookPage />
107	        </div>
108	    }
109	}
