1	use leptos::*;
2	
3	use crate::api::client;
4	use crate::components::nav::Nav;
5	use crate::draft;
6	use crate::pages::{dashboard::DashboardPage, login::LoginPage, register::RegisterPage};
7	use fieldtrace_shared::UserResponse;
8	
9	#[derive(Clone, Debug, PartialEq)]
10	pub enum Page {
11	    Loading,
12	    Login,
13	    Register,
14	    Dashboard,
15	}
16	
17	#[component]
18	pub fn App() -> impl IntoView {
19	    let (page, set_page) = create_signal(Page::Loading);
20	    let (user, set_user) = create_signal(Option::<UserResponse>::None);
21	    let (session_msg, set_session_msg) = create_signal(Option::<String>::None);
22	    // Route we came from before the last session expiry. Populated when
23	    // the user is authenticated (either on initial mount or after login)
24	    // and consumed exactly once.
25	    let (restored_route, set_restored_route) = create_signal(Option::<String>::None);
26	
27	    // On mount: pick up any session-expired flash message from the last
28	    // forced redirect, then check current auth state.
29	    if let Some(flash) = draft::consume_session_flash() {
30	        set_session_msg.set(Some(flash));
31	    }
32	
33	    // Called every time the user transitions from unauthenticated to
34	    // Dashboard — on both initial mount (cookie still valid) and on
35	    // successful login. Consumes the pending route, updates the URL bar,
36	    // and stashes the value in a signal so the dashboard can render a
37	    // "Session restored" banner.
38	    let consume_route_and_restore = move || {
39	        if let Some(route) = draft::consume_pending_route() {
40	            draft::restore_browser_url(&route);
41	            set_restored_route.set(Some(route));
42	        }
43	    };
44	
45	    {
46	        let consume_route_and_restore = consume_route_and_restore.clone();
47	        spawn_local(async move {
48	            match client::get_me().await {
49	                Ok(u) => {
50	                    set_user.set(Some(u));
51	                    // Already authenticated on mount (session cookie survived).
52	                    // Consume any route that was preserved by a prior 401.
53	                    consume_route_and_restore();
54	                    set_page.set(Page::Dashboard);
55	                }
56	                Err(_) => {
57	                    set_page.set(Page::Login);
58	                }
59	            }
60	        });
61	    }
62	
63	    let do_logout = move || {
64	        let set_page = set_page;
65	        let set_user = set_user;
66	        let set_session_msg = set_session_msg;
67	        spawn_local(async move {
68	            let _ = client::logout().await;
69	            set_user.set(None);
70	            set_session_msg.set(Some("You have been logged out.".into()));
71	            set_page.set(Page::Login);
72	        });
73	    };
74	
75	    // Wrapper around the normal login success path — consumes the
76	    // pending route before handing off to the Dashboard view.
77	    let on_login_success = {
78	        let consume_route_and_restore = consume_route_and_restore.clone();
79	        move || {
80	            consume_route_and_restore();
81	        }
82	    };
83	
84	    view! {
85	        {move || {
86	            let p = page.get();
87	            match p {
88	                Page::Loading => view! {
89	                    <div class="center-box">
90	                        <span class="status-indicator status-loading">
91	                            <span class="dot dot-loading"></span>
92	                            "Loading..."
93	                        </span>
94	                    </div>
95	                }.into_view(),
96	
97	                Page::Login => {
98	                    let on_login_success = on_login_success.clone();
99	                    view! {
100	                        <LoginPage
101	                            set_page=set_page
102	                            set_user=set_user
103	                            session_msg=session_msg
104	                            set_session_msg=set_session_msg
105	                            on_login_success=on_login_success
106	                        />
107	                    }.into_view()
108	                },
109	
110	                Page::Register => view! {
111	                    <RegisterPage set_page=set_page set_user=set_user />
112	                }.into_view(),
113	
114	                Page::Dashboard => {
115	                    let restored_route = restored_route;
116	                    view! {
117	                        <Nav user=user on_logout=do_logout.clone() />
118	                        // Visible banner when the app just restored a route.
119	                        // The distinctive prefix literal is what the
120	                        // frontend_draft_test.sh shell test greps for.
121	                        {move || restored_route.get().map(|r| view! {
122	                            <div class="msg msg-info session-restored-banner">
123	                                {format!("{} {}", draft::RESTORE_BANNER_PREFIX, r)}
124	                            </div>
125	                        })}
126	                        <DashboardPage user=user set_page=set_page set_user=set_user />
127	                    }.into_view()
128	                },
129	            }
130	        }}
131	    }
132	}
