15	    let re = zip.len() == 10
16	        && zip.chars().take(5).all(|c| c.is_ascii_digit())
17	        && zip.chars().nth(5) == Some('-')
18	        && zip.chars().skip(6).all(|c| c.is_ascii_digit());
19	    if !re {
20	        return Err(AppError::validation("ZIP+4 must be NNNNN-NNNN format", tid));
21	    }
22	    Ok(())
