23	fn check_size(media_type: &str, size: i64, tid: &str) -> Result<(), AppError> {
24	    let max = match media_type {
25	        "photo" => MAX_PHOTO,
26	        "video" => MAX_VIDEO,
27	        "audio" => MAX_AUDIO,
28	        _ => return Err(AppError::validation("media_type must be photo, video, or audio", tid)),
29	    };
30	    if size > max {
