43	/// Result of applying the local compression policy.
44	#[derive(Debug, Clone)]
45	pub(crate) struct CompressionResult {
46	    pub applied: bool,
47	    pub compressed_bytes: i64,
48	    pub ratio: f64,
49	}
50	
51	/// Deterministic local compression policy.
52	///
53	/// The backend does NOT store raw media bytes (we track metadata only), so
54	/// "compression" here means applying the facility's file-size budget policy
55	/// to the original size. Each media type has a baseline reduction ratio
56	/// that mirrors what a real re-encoder would produce when targetting the
57	/// facility's storage budget:
58	///
59	///   - photo: lossy JPEG re-encode @ quality 80 typically yields ~0.70×
60	///   - video: H.264 reencode to 720p/2Mbps typically yields ~0.60×
61	///   - audio: AAC-LC @ 96kbps typically yields ~0.50×
62	///
63	/// If the original is already at or below a per-type floor (tiny files or
64	/// already highly compressed), the policy decides NOT to re-encode. In that
65	/// case `applied = false` and `compressed_bytes == original`.
66	pub(crate) fn apply_compression_policy(media_type: &str, original_bytes: i64) -> CompressionResult {
67	    // Per-type floor: files this size or smaller are not re-encoded because
68	    // the marginal savings don't justify the CPU cost.
69	    const PHOTO_FLOOR: i64 = 256 * 1024;   // 256 KiB
70	    const VIDEO_FLOOR: i64 = 2 * 1024 * 1024;  // 2 MiB
71	    const AUDIO_FLOOR: i64 = 128 * 1024;   // 128 KiB
72	
73	    let (ratio, floor) = match media_type {
74	        "photo" => (0.70, PHOTO_FLOOR),
75	        "video" => (0.60, VIDEO_FLOOR),
76	        "audio" => (0.50, AUDIO_FLOOR),
77	        _ => (1.00, 0),
78	    };
79	
80	    if original_bytes <= floor || ratio >= 1.0 {
81	        return CompressionResult {
82	            applied: false,
83	            compressed_bytes: original_bytes,
84	            ratio: 1.0,
85	        };
86	    }
87	
88	    // Deterministic integer math so the test can assert exact values.
89	    // ((original * numerator) + denominator/2) / denominator  gives
90	    // rounded-nearest integer compression.
91	    let num = (ratio * 100.0) as i64;
92	    let compressed = (original_bytes * num + 50) / 100;
93	    CompressionResult {
94	        applied: true,
95	        compressed_bytes: compressed,
96	        ratio,
97	    }
98	}
