261	pub async fn list(
262	    State(state): State<AppState>,
263	    Extension(tid): Extension<TraceId>,
264	    Query(q): Query<HashMap<String, String>>,
265	) -> Result<Json<Vec<EvidenceResponse>>, AppError> {
266	    let t = &tid.0;
267	
268	    let mut sql = String::from(
269	        "SELECT id, filename, media_type, watermark_text, missing_exif, linked, legal_hold, created_at, \
270	                size_bytes, compressed_bytes, compression_ratio, compression_applied \
271	         FROM evidence_records WHERE 1=1"
272	    );
273	    let mut binds: Vec<String> = Vec::new();
274	
275	    if let Some(k) = q.get("keyword") {
276	        if !k.is_empty() {
277	            sql.push_str(" AND (keyword LIKE ? OR filename LIKE ?)");
278	            binds.push(format!("%{}%", k));
279	            binds.push(format!("%{}%", k));
280	        }
281	    }
282	    if let Some(tag) = q.get("tag") {
283	        if !tag.is_empty() {
284	            sql.push_str(" AND tags LIKE ?");
285	            binds.push(format!("%{}%", tag));
286	        }
287	    }
288	    if let Some(from) = q.get("from") {
289	        if !from.is_empty() {
290	            sql.push_str(" AND (exif_capture_time >= ? OR created_at >= ?)");
291	            binds.push(from.clone());
292	            binds.push(from.clone());
293	        }
294	    }
295	    if let Some(to) = q.get("to") {
296	        if !to.is_empty() {
297	            sql.push_str(" AND (exif_capture_time <= ? OR created_at <= ?)");
298	            binds.push(to.clone());
299	            binds.push(to.clone());
300	        }
301	    }
302	    sql.push_str(" ORDER BY created_at DESC");
303	
304	    let mut query = sqlx::query_as::<_, EvidenceRow>(&sql);
305	    for b in &binds { query = query.bind(b); }
306	    let rows = query.fetch_all(&state.db).await.map_err(db_err(t))?;
307	
308	    Ok(Json(rows.into_iter().map(|r| {
309	        // Older rows (pre-migration) may not have compression metadata set.
310	        // Fall back to the original size so the response shape is stable.
311	        let compressed_bytes = r.compressed_bytes.unwrap_or(r.size_bytes);
312	        let ratio = r.compression_ratio.unwrap_or(1.0);
313	        EvidenceResponse {
314	            id: r.id, filename: r.filename, media_type: r.media_type,
315	            watermark_text: r.watermark_text, missing_exif: r.missing_exif != 0,
316	            linked: r.linked != 0, legal_hold: r.legal_hold != 0,
317	            created_at: r.created_at,
318	            compressed_bytes,
319	            compression_ratio: ratio,
320	            compression_applied: r.compression_applied != 0,
321	        }
322	    }).collect()))
323	}
