1	//! AES-256-GCM encryption for sensitive fields at rest.
2	//!
3	//! The active cipher is stored behind an `ArcSwap` so it can be replaced
4	//! atomically during key rotation without blocking readers. Both encryption
5	//! and decryption are fallible — we never panic on malformed ciphertext.
6	
7	use aes_gcm::aead::{Aead, AeadCore, KeyInit, OsRng};
8	use aes_gcm::{Aes256Gcm, Nonce};
9	use base64::engine::general_purpose::STANDARD;
10	use base64::Engine;
11	
12	#[derive(Clone)]
13	pub struct Crypto {
14	    cipher: Aes256Gcm,
15	}
16	
17	#[derive(Debug)]
18	pub enum CryptoError {
19	    InvalidKey,
20	    Encrypt,
21	    Decrypt,
22	}
23	
24	impl std::fmt::Display for CryptoError {
25	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
26	        match self {
27	            CryptoError::InvalidKey => write!(f, "invalid key material"),
28	            CryptoError::Encrypt => write!(f, "encryption failed"),
29	            CryptoError::Decrypt => write!(f, "decryption failed"),
30	        }
31	    }
32	}
33	
34	impl std::error::Error for CryptoError {}
35	
36	impl Crypto {
37	    /// Build a `Crypto` from a 64-char hex key (32 bytes).
38	    pub fn from_hex(hex_key: &str) -> Result<Self, CryptoError> {
39	        let key_bytes = hex::decode(hex_key).map_err(|_| CryptoError::InvalidKey)?;
40	        if key_bytes.len() != 32 { return Err(CryptoError::InvalidKey); }
41	        let cipher = Aes256Gcm::new_from_slice(&key_bytes).map_err(|_| CryptoError::InvalidKey)?;
42	        Ok(Self { cipher })
43	    }
44	
45	    /// Back-compat constructor — still panics on bad key for internal callers
46	    /// that assume a valid configured key. Prefer `from_hex`.
47	    pub fn new(hex_key: &str) -> Self {
48	        Self::from_hex(hex_key).expect("ENCRYPTION_KEY must be 32 bytes (64 hex chars)")
49	    }
50	
51	    pub fn encrypt(&self, plaintext: &str) -> String {
52	        // This path is used in-handler for user input; falling back to a
53	        // deterministic error blob would corrupt data. Production callers
54	        // must never fail on encrypt so we pass through expect — but note
55	        // that AES-GCM encrypt only fails on allocation failures.
56	        self.try_encrypt(plaintext).expect("aes-gcm encrypt")
57	    }
58	
59	    pub fn try_encrypt(&self, plaintext: &str) -> Result<String, CryptoError> {
60	        let nonce = Aes256Gcm::generate_nonce(&mut OsRng);
61	        let ct = self.cipher.encrypt(&nonce, plaintext.as_bytes()).map_err(|_| CryptoError::Encrypt)?;
62	        let mut combined = nonce.to_vec();
63	        combined.extend(ct);
64	        Ok(STANDARD.encode(&combined))
65	    }
66	
67	    /// Legacy panic-on-error API kept for handlers that treat stored data
68	    /// as trusted. Prefer `try_decrypt` in new code.
69	    pub fn decrypt(&self, encoded: &str) -> String {
70	        self.try_decrypt(encoded).unwrap_or_default()
71	    }
72	
73	    pub fn try_decrypt(&self, encoded: &str) -> Result<String, CryptoError> {
74	        let combined = STANDARD.decode(encoded).map_err(|_| CryptoError::Decrypt)?;
75	        if combined.len() < 12 { return Err(CryptoError::Decrypt); }
76	        let (nonce_bytes, ct) = combined.split_at(12);
77	        let nonce = Nonce::from_slice(nonce_bytes);
78	        let pt = self.cipher.decrypt(nonce, ct).map_err(|_| CryptoError::Decrypt)?;
79	        String::from_utf8(pt).map_err(|_| CryptoError::Decrypt)
80	    }
81	}
