83	/// Mask a phone number to show only the last 4 digits.
84	pub fn mask_phone(phone: &str) -> String {
85	    let digits: String = phone.chars().filter(|c| c.is_ascii_digit()).collect();
86	    if digits.len() >= 4 {
87	        format!("***-***-{}", &digits[digits.len() - 4..])
88	    } else {
89	        "***-***-****".into()
90	    }
91	}
