1	use serde::{Deserialize, Serialize};
2	
3	// ── Draft autosave / session-expiry restore (pure helpers) ────────────
4	//
5	// Frontend-only feature, but the pure key/serialization logic lives here
6	// in shared so it can be exercised by `cargo test` on the host target
7	// (the frontend crate itself only compiles for wasm32 via trunk).
8	
9	pub const DRAFT_KEY_PREFIX: &str = "fieldtrace.draft.";
10	pub const PENDING_ROUTE_KEY: &str = "fieldtrace.pending_route";
11	pub const SESSION_MSG_KEY: &str = "fieldtrace.session_msg";
12	
13	#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
14	pub struct FormDraft {
15	    pub form_id: String,
16	    pub fields: serde_json::Value,
17	}
18	
19	pub fn draft_key(form_id: &str) -> String {
20	    format!("{}{}", DRAFT_KEY_PREFIX, form_id)
21	}
22	
23	pub fn serialize_draft(form_id: &str, fields: serde_json::Value) -> String {
24	    let d = FormDraft { form_id: form_id.to_string(), fields };
25	    serde_json::to_string(&d).unwrap_or_default()
26	}
27	
28	pub fn deserialize_draft(json: &str) -> Option<FormDraft> {
29	    serde_json::from_str(json).ok()
30	}
31	
32	// ── Storage abstraction so the save/load/preserve/consume round-trip
33	//    can be exercised on the host target (pure cargo test) AND on wasm32
34	//    (web_sys::Storage wrapper in the frontend crate) with the same
35	//    logic path. ────────────────────────────────────────────────────────
36	
37	pub trait DraftStore {
38	    fn get(&self, key: &str) -> Option<String>;
39	    fn set(&self, key: &str, value: &str);
40	    fn remove(&self, key: &str);
41	}
42	
43	/// Persist a form draft snapshot into the given store.
44	pub fn save_draft_to<S: DraftStore>(store: &S, form_id: &str, fields: serde_json::Value) {
45	    store.set(&draft_key(form_id), &serialize_draft(form_id, fields));
46	}
47	
48	/// Read back the previously-saved draft snapshot (fields only).
49	pub fn load_draft_from<S: DraftStore>(store: &S, form_id: &str) -> Option<serde_json::Value> {
50	    let json = store.get(&draft_key(form_id))?;
51	    deserialize_draft(&json).map(|d| d.fields)
52	}
53	
54	/// Remove a draft snapshot (called on successful submit).
55	pub fn clear_draft_from<S: DraftStore>(store: &S, form_id: &str) {
56	    store.remove(&draft_key(form_id));
57	}
58	
59	/// Record the route the user was on when their session expired. The app
60	/// shell re-reads this after login to navigate back.
61	pub fn preserve_route_to<S: DraftStore>(store: &S, route: &str) {
62	    store.set(PENDING_ROUTE_KEY, route);
63	}
64	
65	/// Read-and-clear the preserved route. Returns None if no route was
66	/// pending — this is how the app shell knows "nothing to restore".
67	pub fn consume_pending_route_from<S: DraftStore>(store: &S) -> Option<String> {
68	    let v = store.get(PENDING_ROUTE_KEY);
69	    store.remove(PENDING_ROUTE_KEY);
70	    v
71	}
72	
73	/// Flash a user-visible message that's rendered on the next app mount.
74	pub fn flash_session_expired_to<S: DraftStore>(store: &S, msg: &str) {
75	    store.set(SESSION_MSG_KEY, msg);
76	}
77	
78	/// Read-and-clear the session-expired flash message.
79	pub fn consume_session_flash_from<S: DraftStore>(store: &S) -> Option<String> {
80	    let v = store.get(SESSION_MSG_KEY);
81	    store.remove(SESSION_MSG_KEY);
82	    v
83	}
