60	pub async fn checkin(
61	    State(state): State<AppState>,
62	    Extension(tid): Extension<TraceId>,
63	    Extension(user): Extension<SessionUser>,
64	    Json(body): Json<CheckinRequest>,
65	) -> Result<(StatusCode, Json<CheckinResponse>), AppError> {
66	    let t = &tid.0;
67	    require_write_role(&user, t)?;
68	
69	    // Find member
70	    let member: Option<(String,)> = sqlx::query_as("SELECT id FROM members WHERE member_id = ?")
71	        .bind(&body.member_id).fetch_optional(&state.db).await
72	        .map_err(db_err(t))?;
73	    let (member_uuid,) = member.ok_or_else(|| AppError::not_found("Member not found", t))?;
74	
75	    // Anti-passback check (unless override)
76	    if body.override_reason.is_none() {
77	        // Fetch the most recent checkin within the anti-passback window and
78	        // compute the remaining wait.
79	        let recent: Option<(String, i64)> = sqlx::query_as(
80	            "SELECT checked_in_at, CAST((strftime('%s','now') - strftime('%s', checked_in_at)) AS INTEGER) \
81	             FROM checkin_ledger \
82	             WHERE member_id = ? AND facility_id = 'default' \
83	               AND checked_in_at > datetime('now', '-120 seconds') \
84	             ORDER BY checked_in_at DESC LIMIT 1"
85	        ).bind(&member_uuid).fetch_optional(&state.db).await
86	            .map_err(db_err(t))?;
87	
88	        if let Some((_last_at, elapsed)) = recent {
89	            let retry_after = (ANTI_PASSBACK_SECONDS - elapsed).max(1);
90	            return Err(AppError::custom(
91	                StatusCode::CONFLICT,
92	                "ANTI_PASSBACK",
93	                format!("Re-entry blocked. Retry in {} seconds.", retry_after),
94	                t,
95	            ).with_extra(serde_json::json!({ "retry_after_seconds": retry_after })));
96	        }
97	    } else {
98	        // Only admin can override
99	        if !is_admin(&user) {
100	            return Err(AppError::forbidden("Only Administrator can override anti-passback", t));
101	        }
102	    }
103	
104	    let id = Uuid::new_v4().to_string();
105	    sqlx::query("INSERT INTO checkin_ledger (id, member_id, override_reason, override_by) VALUES (?,?,?,?)")
106	        .bind(&id).bind(&member_uuid).bind(&body.override_reason).bind(&user.user_id)
107	        .execute(&state.db).await
108	        .map_err(db_err(t))?;
109	
110	    crate::modules::audit::write(
111	        &state.db, &user.user_id,
112	        if body.override_reason.is_some() { "checkin.override" } else { "checkin.create" },
113	        "checkin", &id, t,
114	    ).await;
115	
116	    Ok((StatusCode::CREATED, Json(CheckinResponse {
117	        id, member_id: body.member_id, checked_in_at: String::new(),
118	        was_override: body.override_reason.is_some(),
119	    })))
120	}
