45	    let (canonical_size, size_conflict) = match parser::normalize_size(&body.size) {
46	        Some(s) => (Some(s), None),
47	        None => (None, Some("size")),
48	    };
49	
50	    let mut conflicts: HashMap<String, String> = HashMap::new();
51	    if let Some(f) = color_conflict { conflicts.insert(f.into(), format!("Unknown color: {}", body.color)); }
52	    if let Some(f) = size_conflict { conflicts.insert(f.into(), format!("Cannot parse size: {}", body.size)); }
53	
54	    let parse_status = if conflicts.is_empty() { "ok" } else { "needs_review" };
55	    let conflicts_json = serde_json::to_string(&conflicts).unwrap_or("{}".into());
56	
57	    let id = Uuid::new_v4().to_string();
58	    sqlx::query(
59	        "INSERT INTO supply_entries (id, name, sku, raw_size, canonical_size, raw_color, canonical_color, price_cents, discount_cents, notes, parse_status, parse_conflicts, created_by) \
60	         VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?)"
61	    )
62	    .bind(&id).bind(&body.name).bind(&body.sku).bind(&body.size).bind(&canonical_size)
63	    .bind(&body.color).bind(&canonical_color).bind(body.price_cents).bind(body.discount_cents)
64	    .bind(&body.notes).bind(parse_status).bind(&conflicts_json).bind(&user.user_id)
