9	//! - `tags`                 — substring match against CSV tag column
10	//! - `q`                    — full-text substring search against details/region/tags
11	//!
12	//! `inventory_on_hand` is sourced from the `stock_movements` ledger
13	//! (SUM of quantity_delta), NOT `COUNT(supply_entries)`.
14	
15	use axum::extract::{Query, State};
16	use axum::http::{header, HeaderMap, HeaderValue, StatusCode};
17	use axum::response::IntoResponse;
18	use axum::{Extension, Json};
19	use std::collections::HashMap;
