27	#[derive(Default, Clone)]
28	struct DashboardFilters {
29	    from: String,
30	    to: String,
31	    status: String,
32	    intake_type: String,
33	    region: String,
34	    tags: String,
35	    q: String,
36	}
37	
38	impl DashboardFilters {
39	    fn from_query(q: &HashMap<String, String>) -> Self {
40	        Self {
41	            from: q.get("from").cloned().unwrap_or_default(),
42	            to: q.get("to").cloned().unwrap_or_default(),
43	            status: q.get("status").cloned().unwrap_or_default(),
44	            intake_type: q.get("intake_type").cloned().unwrap_or_default(),
45	            region: q.get("region").cloned().unwrap_or_default(),
46	            tags: q.get("tags").cloned().unwrap_or_default(),
47	            q: q.get("q").cloned().unwrap_or_default(),
48	        }
49	    }
50	
51	    /// Builds the shared `WHERE` fragment + bind list used by every
52	    /// count query. A single source of truth so summary + export
53	    /// ALWAYS honor the exact same filter semantics.
54	    fn where_clause(&self) -> (String, Vec<String>) {
55	        let mut parts: Vec<String> = vec!["1=1".into()];
56	        let mut binds: Vec<String> = Vec::new();
57	        if !self.from.is_empty() {
58	            parts.push("created_at >= ?".into());
59	            binds.push(self.from.clone());
60	        }
61	        if !self.to.is_empty() {
62	            parts.push("created_at <= ?".into());
63	            binds.push(self.to.clone());
64	        }
65	        if !self.intake_type.is_empty() {
66	            parts.push("intake_type = ?".into());
67	            binds.push(self.intake_type.clone());
68	        }
69	        if !self.status.is_empty() {
70	            parts.push("status = ?".into());
71	            binds.push(self.status.clone());
72	        }
73	        if !self.region.is_empty() {
74	            parts.push("region = ?".into());
75	            binds.push(self.region.clone());
76	        }
77	        if !self.tags.is_empty() {
78	            parts.push("tags LIKE ?".into());
79	            binds.push(format!("%{}%", self.tags));
80	        }
81	        if !self.q.is_empty() {
82	            // Simple substring "full-text" across the free-form fields.
83	            parts.push("(details LIKE ? OR region LIKE ? OR tags LIKE ?)".into());
84	            let pat = format!("%{}%", self.q);
85	            binds.push(pat.clone());
86	            binds.push(pat.clone());
87	            binds.push(pat);
88	        }
89	        (parts.join(" AND "), binds)
90	    }
91	}
