93	pub async fn summary(
94	    State(state): State<AppState>,
95	    Extension(tid): Extension<TraceId>,
96	    Query(q): Query<HashMap<String, String>>,
97	) -> Result<Json<serde_json::Value>, AppError> {
98	    let t = &tid.0;
99	    let filters = DashboardFilters::from_query(&q);
100	    let metrics = compute_metrics(&state, t, &filters).await?;
101	    Ok(Json(serde_json::to_value(metrics).unwrap()))
102	}
