104	#[derive(serde::Serialize)]
105	struct Metrics {
106	    rescue_volume: i64,
107	    adoption_conversion: f64,
108	    task_completion_rate: f64,
109	    donations_logged: i64,
110	    inventory_on_hand: i64,
111	    filters: serde_json::Value,
112	}
113	
114	async fn count_with(
115	    pool: &sqlx::SqlitePool,
116	    sql: String,
117	    binds: &[String],
118	    t: &str,
119	) -> Result<i64, AppError> {
120	    let mut q = sqlx::query_as::<_, (i64,)>(&sql);
121	    for b in binds {
122	        q = q.bind(b);
123	    }
124	    let (n,) = q.fetch_one(pool).await.map_err(db_err(t))?;
125	    Ok(n)
126	}
127	
128	async fn compute_metrics(
129	    state: &AppState,
130	    t: &str,
131	    f: &DashboardFilters,
132	) -> Result<Metrics, AppError> {
133	    let (where_sql, binds) = f.where_clause();
134	
135	    let intake_total = count_with(
136	        &state.db,
137	        format!("SELECT COUNT(*) FROM intake_records WHERE {}", where_sql),
138	        &binds,
139	        t,
140	    )
141	    .await?;
142	
143	    let mut donations_binds = binds.clone();
144	    donations_binds.push("donation".into());
145	    let donations = count_with(
146	        &state.db,
147	        format!(
148	            "SELECT COUNT(*) FROM intake_records WHERE {} AND intake_type = ?",
149	            where_sql
150	        ),
151	        &donations_binds,
152	        t,
153	    )
154	    .await?;
155	
156	    let mut animals_binds = binds.clone();
157	    animals_binds.push("animal".into());
158	    let animals = count_with(
159	        &state.db,
160	        format!(
161	            "SELECT COUNT(*) FROM intake_records WHERE {} AND intake_type = ?",
162	            where_sql
163	        ),
164	        &animals_binds,
165	        t,
166	    )
167	    .await?;
168	
169	    let mut adopted_binds = binds.clone();
170	    adopted_binds.push("adopted".into());
171	    let adopted = count_with(
172	        &state.db,
173	        format!(
174	            "SELECT COUNT(*) FROM intake_records WHERE {} AND status = ?",
175	            where_sql
176	        ),
177	        &adopted_binds,
178	        t,
179	    )
180	    .await?;
181	
182	    let tasks_done: (i64,) = sqlx::query_as("SELECT COUNT(*) FROM tasks WHERE status = 'completed'")
183	        .fetch_one(&state.db)
184	        .await
185	        .map_err(db_err(t))?;
186	    let tasks_open: (i64,) = sqlx::query_as("SELECT COUNT(*) FROM tasks WHERE status IN ('open','in_progress')")
187	        .fetch_one(&state.db)
188	        .await
189	        .map_err(db_err(t))?;
190	
191	    // Inventory on hand: canonical source is the stock_movements ledger.
192	    // NOT COUNT(supply_entries) any more.
193	    let inventory_on_hand = crate::modules::stock::handlers::sum_on_hand(&state.db)
194	        .await
195	        .map_err(db_err(t))?;
196	
197	    let adoption_conversion = if animals > 0 { adopted as f64 / animals as f64 } else { 0.0 };
198	    let task_completion_rate = if tasks_done.0 + tasks_open.0 > 0 {
199	        tasks_done.0 as f64 / (tasks_done.0 + tasks_open.0) as f64
200	    } else {
201	        0.0
202	    };
203	
204	    Ok(Metrics {
205	        rescue_volume: intake_total,
206	        adoption_conversion,
207	        task_completion_rate,
208	        donations_logged: donations,
209	        inventory_on_hand,
210	        filters: serde_json::json!({
211	            "from": f.from,
212	            "to": f.to,
213	            "status": f.status,
214	            "intake_type": f.intake_type,
215	            "region": f.region,
216	            "tags": f.tags,
217	            "q": f.q,
218	        }),
219	    })
220	}
221	
222	pub async fn export_csv(
223	    State(state): State<AppState>,
224	    Extension(tid): Extension<TraceId>,
225	    Extension(user): Extension<SessionUser>,
226	    Query(q): Query<HashMap<String, String>>,
227	) -> Result<impl IntoResponse, AppError> {
228	    let t = &tid.0;
229	    require_admin_or_auditor(&user, t)?;
230	
231	    // Export uses the EXACT same filter set as summary — same parser,
232	    // same WHERE builder — so operators can't accidentally get a
233	    // different result from the CSV than what they see on screen.
234	    let filters = DashboardFilters::from_query(&q);
235	    let m = compute_metrics(&state, t, &filters).await?;
236	
237	    let csv = format!(
238	        "metric,value\nrescue_volume,{}\ndonations_logged,{}\ninventory_on_hand,{}\nadoption_conversion,{}\ntask_completion_rate,{}\nfilter_region,{}\nfilter_tags,{}\nfilter_q,{}\n",
239	        m.rescue_volume,
240	        m.donations_logged,
241	        m.inventory_on_hand,
242	        m.adoption_conversion,
243	        m.task_completion_rate,
244	        filters.region,
245	        filters.tags,
246	        filters.q,
247	    );
248	
249	    let mut headers = HeaderMap::new();
250	    headers.insert(header::CONTENT_TYPE, HeaderValue::from_static("text/csv"));
251	    headers.insert(
252	        "Content-Disposition",
253	        HeaderValue::from_static("attachment; filename=\"report.csv\""),
254	    );
255	    Ok((StatusCode::OK, headers, csv))
256	}
257	
258	pub async fn adoption_conversion(
259	    State(state): State<AppState>,
260	    Extension(tid): Extension<TraceId>,
261	) -> Result<Json<serde_json::Value>, AppError> {
262	    let t = &tid.0;
263	    let animals: (i64,) = sqlx::query_as("SELECT COUNT(*) FROM intake_records WHERE intake_type = 'animal'")
264	        .fetch_one(&state.db)
265	        .await
266	        .map_err(db_err(t))?;
267	    let adopted: (i64,) = sqlx::query_as("SELECT COUNT(*) FROM intake_records WHERE status = 'adopted'")
268	        .fetch_one(&state.db)
269	        .await
270	        .map_err(db_err(t))?;
271	    let rate = if animals.0 > 0 {
272	        (adopted.0 as f64) / (animals.0 as f64)
273	    } else {
274	        0.0
275	    };
276	    Ok(Json(serde_json::json!({
277	        "total": animals.0,
278	        "adopted": adopted.0,
279	        "conversion_rate": rate,
280	    })))
281	}
