125	        ));
126	    }
127	
128	    sqlx::query("UPDATE intake_records SET status = ?, updated_at = datetime('now') WHERE id = ?")
129	        .bind(&body.status).bind(&id).execute(&state.db).await
130	        .map_err(db_err(t))?;
