44	        Self { status: StatusCode::BAD_REQUEST, code: "VALIDATION_ERROR", message: msg.into(), trace_id: tid.into(), extra: Map::new() }
45	    }
46	    pub fn unauthorized(msg: impl Into<String>, tid: impl Into<String>) -> Self {
47	        Self { status: StatusCode::UNAUTHORIZED, code: "UNAUTHORIZED", message: msg.into(), trace_id: tid.into(), extra: Map::new() }
48	    }
