1	//! Cross-cutting utilities: error sanitization, date formatting, role helpers.
2	//!
3	//! ## Error sanitization
4	//!
5	//! DB and system errors must NEVER propagate their raw `Display` output to
6	//! clients. This module wraps the common "map_err → AppError::internal"
7	//! pattern into `db_err(trace_id)` / `system_err(trace_id)` helpers that log
8	//! full detail via `tracing::error!` and return a generic user-facing message.
9	//!
10	//! ## Local date/time formatting
11	//!
12	//! Evidence watermark and traceability codes need real local dates without a
13	//! chrono dependency. We compute civil date/time fields directly from
14	//! `SystemTime` using the standard proleptic Gregorian calendar.
15	
16	use crate::error::AppError;
17	use crate::extractors::SessionUser;
18	use sqlx::SqlitePool;
19	use std::time::{SystemTime, UNIX_EPOCH};
20	
21	// ── Structured log persistence ────────────────────────────────────────
22	//
23	// Writes a row into the `structured_logs` table. This is on top of the
24	// `tracing` subscriber which emits JSON to stdout — the DB copy lets the
25	// diagnostics ZIP bundle the last 7 days of local activity even when the
26	// container's stdout history has been rotated.
27	//
28	// The caller is responsible for keeping `message` free of secrets.
29	// `sanitize_message` below blocks obviously sensitive substrings as a
30	// defense in depth.
31	
32	/// Substrings we never allow inside a structured_logs `message` field.
33	const SENSITIVE_MARKERS: &[&str] = &[
34	    "password", "Password", "PASSWORD",
35	    "session_id=", "session=", "bearer ", "Bearer ",
36	    "Authorization:", "authorization:",
37	    "token=", "api_key=", "apikey=",
38	    "$argon2", "secret=",
39	];
40	
41	/// Drops or masks sensitive substrings. We refuse to log anything that
42	/// looks like a credential — the message is replaced with a safe marker.
43	pub fn sanitize_log_message(msg: &str) -> String {
44	    for marker in SENSITIVE_MARKERS {
45	        if msg.contains(marker) {
46	            return "[REDACTED: sensitive content blocked]".into();
47	        }
48	    }
49	    // Also cap length to prevent log poisoning.
50	    if msg.len() > 2000 { msg.chars().take(2000).collect() } else { msg.to_string() }
51	}
52	
53	/// Fire-and-forget write to structured_logs. Silently swallows errors
54	/// because logging failures must never break the business flow.
55	pub async fn slog(db: &SqlitePool, level: &str, message: &str, trace_id: &str) {
56	    let safe = sanitize_log_message(message);
57	    let _ = sqlx::query(
58	        "INSERT INTO structured_logs (level, message, trace_id) VALUES (?, ?, ?)"
59	    )
60	    .bind(level)
61	    .bind(&safe)
62	    .bind(trace_id)
63	    .execute(db)
64	    .await;
65	}
66	
67	// ── Error sanitization ────────────────────────────────────────────────
68	
69	/// Returns a mapping closure that logs the full DB error and yields a
70	/// sanitized AppError::internal response (no raw `Display` leaked).
71	pub fn db_err<E: std::fmt::Display>(trace_id: &str) -> impl Fn(E) -> AppError + '_ {
72	    let tid = trace_id.to_string();
73	    move |e| {
74	        tracing::error!(trace_id = %tid, error = %e, "Database error");
75	        AppError::internal("Internal server error", tid.clone())
76	    }
77	}
78	
79	/// System-level (I/O, crypto, other) error sanitizer.
80	pub fn system_err<'a, E: std::fmt::Display>(
81	    trace_id: &'a str,
82	    context: &'static str,
83	) -> impl Fn(E) -> AppError + 'a {
84	    let tid = trace_id.to_string();
85	    move |e| {
86	        tracing::error!(trace_id = %tid, context = %context, error = %e, "System error");
87	        AppError::internal("Internal server error", tid.clone())
88	    }
89	}
