93	pub fn is_admin(u: &SessionUser) -> bool { u.role == "administrator" }
94	pub fn is_staff(u: &SessionUser) -> bool { u.role == "operations_staff" }
95	pub fn is_auditor(u: &SessionUser) -> bool { u.role == "auditor" }
