116	// ── Local date/time formatting (no chrono) ────────────────────────────
117	
118	/// Civil date computed from a Unix timestamp (UTC — acceptable for an
119	/// offline facility app where local = facility time).
120	#[derive(Debug, Clone, Copy)]
121	pub struct CivilDateTime {
122	    pub year: i32,
123	    pub month: u8,
124	    pub day: u8,
125	    pub hour: u8,
126	    pub minute: u8,
127	    pub second: u8,
128	}
129	
130	impl CivilDateTime {
131	    pub fn from_unix(ts: i64) -> Self {
132	        // Days since Unix epoch (1970-01-01).
133	        let secs_per_day = 86_400i64;
134	        let mut days = ts.div_euclid(secs_per_day);
135	        let mut secs_of_day = ts.rem_euclid(secs_per_day) as i32;
136	        if secs_of_day < 0 { secs_of_day += secs_per_day as i32; days -= 1; }
137	
138	        // Civil from days algorithm by Howard Hinnant.
139	        let z = days + 719_468; // shift epoch to 0000-03-01
140	        let era = if z >= 0 { z } else { z - 146096 } / 146097;
141	        let doe = (z - era * 146097) as u32; // [0, 146096]
142	        let yoe = (doe - doe / 1460 + doe / 36524 - doe / 146096) / 365; // [0, 399]
143	        let y = yoe as i32 + era as i32 * 400;
144	        let doy = doe - (365 * yoe + yoe / 4 - yoe / 100); // [0, 365]
145	        let mp = (5 * doy + 2) / 153; // [0, 11]
146	        let d = (doy - (153 * mp + 2) / 5 + 1) as u8; // [1, 31]
147	        let m = (if mp < 10 { mp + 3 } else { mp - 9 }) as u8; // [1, 12]
148	        let year = if m <= 2 { y + 1 } else { y };
149	
150	        let hour = (secs_of_day / 3600) as u8;
151	        let minute = ((secs_of_day % 3600) / 60) as u8;
152	        let second = (secs_of_day % 60) as u8;
153	
154	        CivilDateTime { year, month: m, day: d, hour, minute, second }
155	    }
156	
157	    pub fn now() -> Self {
158	        let ts = SystemTime::now().duration_since(UNIX_EPOCH).map(|d| d.as_secs() as i64).unwrap_or(0);
159	        Self::from_unix(ts)
160	    }
161	
162	    /// `YYYYMMDD`
163	    pub fn yyyymmdd(&self) -> String {
164	        format!("{:04}{:02}{:02}", self.year, self.month, self.day)
165	    }
166	
167	    /// `MM/DD/YYYY hh:mm AM/PM` (12-hour clock)
168	    pub fn us_12h(&self) -> String {
169	        let (h12, ampm) = match self.hour {
170	            0 => (12u8, "AM"),
171	            h if h < 12 => (h, "AM"),
172	            12 => (12, "PM"),
173	            h => (h - 12, "PM"),
174	        };
175	        format!("{:02}/{:02}/{:04} {:02}:{:02} {}",
176	            self.month, self.day, self.year, h12, self.minute, ampm)
177	    }
178	}
