8	#[component]
9	pub fn IntakePage() -> impl IntoView {
10	    let (entries, set_entries) = create_signal(Vec::<IntakeResponse>::new());
11	    let (show_form, set_show_form) = create_signal(false);
12	
13	    let refresh = move || {
14	        spawn_local(async move {
15	            if let Ok(list) = client::list_intake().await { set_entries.set(list); }
16	        });
17	    };
18	    refresh();
19	
20	    // If a draft is present (from a previous session that timed out)
21	    // open the form automatically so the user sees their preserved input.
22	    if draft::load_draft(INTAKE_FORM_ID).is_some() {
23	        set_show_form.set(true);
24	    }
25	
26	    view! {
27	        <div class="card">
28	            <h2>"Intake Records"</h2>
29	            <button class="btn" on:click=move |_| set_show_form.update(|v| *v = !*v)>
30	                {move || if show_form.get() { "Cancel" } else { "New Intake" }}
31	            </button>
32	            {move || show_form.get().then(|| {
33	                let refresh = refresh.clone();
34	                let set_show = set_show_form;
35	                view! { <IntakeForm on_done=move || { refresh(); set_show.set(false); } /> }
36	            })}
37	            <div class="list">
38	                {move || entries.get().into_iter().map(|r| {
39	                    let id = r.id.clone();
40	                    let status_class = match r.status.as_str() {
41	                        "received" => "tag-info",
42	                        "adopted" => "tag-ok",
43	                        _ => "tag-default",
44	                    };
45	                    view! {
46	                        <div class="list-item">
47	                            <strong>{r.intake_type.clone()}</strong>
48	                            <span class={format!("tag {}", status_class)}>{r.status.clone()}</span>
49	                            <span class="muted">" ID: "{id}</span>
50	                        </div>
51	                    }
52	                }).collect_view()}
53	            </div>
54	        </div>
55	    }
56	}
57	
58	#[component]
59	fn IntakeForm<F: Fn() + Clone + 'static>(on_done: F) -> impl IntoView {
60	    // Seed from any preserved draft. This is what makes a forced re-login
61	    // round-trip with the user's typing still in the form.
62	    let restored = draft::load_draft(INTAKE_FORM_ID);
63	    let pick = |k: &str, default: &str| -> String {
64	        restored.as_ref()
65	            .and_then(|v| v.get(k).and_then(|s| s.as_str().map(String::from)))
66	            .unwrap_or_else(|| default.to_string())
67	    };
68	
69	    let (itype, set_itype) = create_signal(pick("intake_type", "animal"));
70	    let (details, set_details) = create_signal(pick("details", ""));
71	    let (region, set_region) = create_signal(pick("region", ""));
72	    let (tags, set_tags) = create_signal(pick("tags", ""));
73	    let (err, set_err) = create_signal(Option::<String>::None);
74	
75	    // Autosave on every field change. Cheap — just a JSON write to
76	    // localStorage.
77	    create_effect(move |_| {
78	        let snapshot = serde_json::json!({
79	            "intake_type": itype.get(),
80	            "details": details.get(),
81	            "region": region.get(),
82	            "tags": tags.get(),
83	        });
84	        draft::save_draft(INTAKE_FORM_ID, snapshot);
85	    });
86	
87	    let submit = move |ev: leptos::ev::SubmitEvent| {
88	        ev.prevent_default();
89	        let req = IntakeRequest {
90	            intake_type: itype.get(),
91	            details: details.get(),
92	            region: region.get(),
93	            tags: tags.get(),
94	        };
95	        let on_done = on_done.clone();
96	        spawn_local(async move {
97	            match client::create_intake(&req).await {
98	                Ok(_) => {
99	                    draft::clear_draft(INTAKE_FORM_ID);
100	                    on_done();
101	                }
102	                Err(e) => set_err.set(Some(e.message)),
103	            }
104	        });
105	    };
106	
107	    view! {
108	        <form class="addr-form" on:submit=submit>
109	            {move || err.get().map(|e| view! { <div class="msg msg-error">{e}</div> })}
110	            <select on:change=move |e| set_itype.set(event_target_value(&e))>
111	                <option value="animal">"Animal"</option>
112	                <option value="supply">"Supply"</option>
113	                <option value="donation">"Donation"</option>
114	            </select>
115	            <input placeholder="Details (JSON)" prop:value=details
116	                on:input=move |e| set_details.set(event_target_value(&e)) />
117	            <input placeholder="Region (e.g. north, warehouse-2)" prop:value=region
118	                on:input=move |e| set_region.set(event_target_value(&e)) />
119	            <input placeholder="Tags (comma-separated)" prop:value=tags
120	                on:input=move |e| set_tags.set(event_target_value(&e)) />
121	            <button type="submit" class="btn">"Create Intake"</button>
122	        </form>
123	    }
124	}
