1	//! Draft autosave + session-expiry restore (WASM side).
2	//!
3	//! All business logic lives in `fieldtrace-shared` behind a `DraftStore`
4	//! trait so `cargo test -p fieldtrace-shared` exercises the full
5	//! preserve/consume round-trip with an in-memory mock store on the host
6	//! target. The only thing this file does is wrap `web_sys::Storage`
7	//! with an impl of that trait and expose the thin `save_draft`/
8	//! `load_draft`/`preserve_route`/`consume_pending_route` helpers that
9	//! the intake/address forms and the app shell import.
10	
11	#[allow(unused_imports)]
12	use fieldtrace_shared::{
13	    clear_draft_from, consume_pending_route_from, consume_session_flash_from,
14	    flash_session_expired_to, load_draft_from, preserve_route_to, save_draft_to,
15	    DraftStore, DRAFT_KEY_PREFIX, PENDING_ROUTE_KEY, SESSION_MSG_KEY,
16	};
17	
18	/// Distinct literal embedded in the WASM bundle so the integration test
19	/// can prove the restore call site was not dead-code-eliminated. The
20	/// banner shown to the user after a successful re-login uses this
21	/// exact string prefix.
22	pub const RESTORE_BANNER_PREFIX: &str = "fieldtrace.session_restored_from:";
23	
24	#[cfg(target_arch = "wasm32")]
25	struct WebStorage(web_sys::Storage);
26	
27	#[cfg(target_arch = "wasm32")]
28	impl DraftStore for WebStorage {
29	    fn get(&self, key: &str) -> Option<String> {
30	        self.0.get_item(key).ok().flatten()
31	    }
32	    fn set(&self, key: &str, value: &str) {
33	        let _ = self.0.set_item(key, value);
34	    }
35	    fn remove(&self, key: &str) {
36	        let _ = self.0.remove_item(key);
37	    }
38	}
39	
40	#[cfg(target_arch = "wasm32")]
41	fn storage() -> Option<WebStorage> {
42	    web_sys::window()?
43	        .local_storage()
44	        .ok()
45	        .flatten()
46	        .map(WebStorage)
47	}
48	
49	// ── WASM helpers: thin wrappers over the shared DraftStore API ────────
50	
51	#[cfg(target_arch = "wasm32")]
52	pub fn save_draft(form_id: &str, fields: serde_json::Value) {
53	    if let Some(s) = storage() {
54	        save_draft_to(&s, form_id, fields);
55	    }
56	}
57	
58	#[cfg(target_arch = "wasm32")]
59	pub fn load_draft(form_id: &str) -> Option<serde_json::Value> {
60	    storage().and_then(|s| load_draft_from(&s, form_id))
61	}
62	
63	#[cfg(target_arch = "wasm32")]
64	pub fn clear_draft(form_id: &str) {
65	    if let Some(s) = storage() {
66	        clear_draft_from(&s, form_id);
67	    }
68	}
69	
70	#[cfg(target_arch = "wasm32")]
71	pub fn preserve_route(route: &str) {
72	    if let Some(s) = storage() {
73	        preserve_route_to(&s, route);
74	    }
75	}
76	
77	#[cfg(target_arch = "wasm32")]
78	pub fn consume_pending_route() -> Option<String> {
79	    storage().and_then(|s| consume_pending_route_from(&s))
80	}
81	
82	#[cfg(target_arch = "wasm32")]
83	pub fn flash_session_expired() {
84	    if let Some(s) = storage() {
