4	// ── Error type ──────────────────────────────────────────────────────
5	
6	#[derive(Debug, Clone)]
7	pub struct ApiError {
8	    pub status: u16,
9	    pub code: String,
10	    pub message: String,
11	}
12	
13	impl std::fmt::Display for ApiError {
14	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
15	        write!(f, "{}", self.message)
16	    }
17	}
18	
19	async fn parse_error(resp: gloo_net::http::Response) -> ApiError {
20	    let status = resp.status();
21	    // Session expired mid-action: flash a user-visible message and preserve
22	    // the current route so the app shell can restore the same page after
23	    // re-login. Any active draft stays in localStorage untouched.
24	    if status == 401 {
25	        crate::draft::flash_session_expired();
26	        // Best-effort route capture — the browser's location hash/path is
27	        // what the app shell uses as its route key.
28	        #[cfg(target_arch = "wasm32")]
29	        if let Some(w) = web_sys::window() {
30	            if let Ok(p) = w.location().pathname() {
31	                crate::draft::preserve_route(&p);
32	            }
33	        }
34	    }
35	    match resp.json::<ErrorResponse>().await {
36	        Ok(e) => ApiError { status: e.status, code: e.code, message: e.message },
37	        Err(_) => ApiError { status, code: "UNKNOWN".into(), message: format!("HTTP {}", status) },
38	    }
39	}
