14	// Size limits (bytes)
15	const MAX_PHOTO: i64 = 25 * 1024 * 1024;
16	const MAX_VIDEO: i64 = 150 * 1024 * 1024;
17	const MAX_AUDIO: i64 = 20 * 1024 * 1024;
18	const MAX_VIDEO_SECONDS: i64 = 60;
19	const MAX_AUDIO_SECONDS: i64 = 120;
