21	fn check_size(media_type: &str, size: i64, tid: &str) -> Result<(), AppError> {
22	    let max = match media_type {
23	        "photo" => MAX_PHOTO,
24	        "video" => MAX_VIDEO,
25	        "audio" => MAX_AUDIO,
26	        _ => return Err(AppError::validation("media_type must be photo, video, or audio", tid)),
27	    };
28	    if size > max {
29	        return Err(AppError::validation(format!("File exceeds {} bytes for {}", max, media_type), tid));
30	    }
31	    Ok(())
32	}
