41	/// Result of applying the local compression policy.
42	#[derive(Debug, Clone)]
43	pub(crate) struct CompressionResult {
44	    pub applied: bool,
45	    pub compressed_bytes: i64,
46	    pub ratio: f64,
47	}
48	
49	/// Deterministic local compression policy.
50	///
51	/// The backend does NOT store raw media bytes (we track metadata only), so
52	/// "compression" here means applying the facility's file-size budget policy
53	/// to the original size. Each media type has a baseline reduction ratio
54	/// that mirrors what a real re-encoder would produce when targetting the
55	/// facility's storage budget:
56	///
57	///   - photo: lossy JPEG re-encode @ quality 80 typically yields ~0.70×
58	///   - video: H.264 reencode to 720p/2Mbps typically yields ~0.60×
59	///   - audio: AAC-LC @ 96kbps typically yields ~0.50×
60	///
61	/// If the original is already at or below a per-type floor (tiny files or
62	/// already highly compressed), the policy decides NOT to re-encode. In that
63	/// case `applied = false` and `compressed_bytes == original`.
64	pub(crate) fn apply_compression_policy(media_type: &str, original_bytes: i64) -> CompressionResult {
65	    // Per-type floor: files this size or smaller are not re-encoded because
66	    // the marginal savings don't justify the CPU cost.
67	    const PHOTO_FLOOR: i64 = 256 * 1024;   // 256 KiB
68	    const VIDEO_FLOOR: i64 = 2 * 1024 * 1024;  // 2 MiB
69	    const AUDIO_FLOOR: i64 = 128 * 1024;   // 128 KiB
70	
71	    let (ratio, floor) = match media_type {
72	        "photo" => (0.70, PHOTO_FLOOR),
73	        "video" => (0.60, VIDEO_FLOOR),
74	        "audio" => (0.50, AUDIO_FLOOR),
75	        _ => (1.00, 0),
76	    };
77	
78	    if original_bytes <= floor || ratio >= 1.0 {
79	        return CompressionResult {
80	            applied: false,
81	            compressed_bytes: original_bytes,
82	            ratio: 1.0,
83	        };
84	    }
85	
86	    // Deterministic integer math so the test can assert exact values.
87	    // ((original * numerator) + denominator/2) / denominator  gives
88	    // rounded-nearest integer compression.
89	    let num = (ratio * 100.0) as i64;
90	    let compressed = (original_bytes * num + 50) / 100;
91	    CompressionResult {
92	        applied: true,
93	        compressed_bytes: compressed,
94	        ratio,
95	    }
96	}
