98	// POST /media/upload/start — create upload session
99	pub async fn upload_start(
100	    State(state): State<AppState>,
101	    Extension(tid): Extension<TraceId>,
102	    Extension(user): Extension<SessionUser>,
103	    Json(body): Json<UploadStartRequest>,
104	) -> Result<Json<UploadStartResponse>, AppError> {
105	    let t = &tid.0;
106	    require_write_role(&user, t)?;
107	    check_size(&body.media_type, body.total_size, t)?;
108	    if body.media_type == "video" && body.duration_seconds > MAX_VIDEO_SECONDS {
109	        return Err(AppError::validation("Video exceeds 60 seconds", t));
110	    }
111	    if body.media_type == "audio" && body.duration_seconds > MAX_AUDIO_SECONDS {
112	        return Err(AppError::validation("Audio exceeds 2 minutes", t));
113	    }
114	    let id = Uuid::new_v4().to_string();
115	    let total_chunks = (body.total_size + (2 * 1024 * 1024) - 1) / (2 * 1024 * 1024);
116	    sqlx::query("INSERT INTO upload_sessions (id, filename, media_type, total_chunks, uploader_id) VALUES (?,?,?,?,?)")
117	        .bind(&id).bind(&body.filename).bind(&body.media_type)
118	        .bind(total_chunks).bind(&user.user_id)
119	        .execute(&state.db).await
120	        .map_err(db_err(t))?;
121	    Ok(Json(UploadStartResponse { upload_id: id, chunk_size_bytes: 2 * 1024 * 1024, total_chunks }))
122	}
