124	/// Recognized media magic-byte signatures for format validation.
125	fn validate_media_format(media_type: &str, data: &[u8]) -> bool {
126	    if data.len() < 4 { return false; }
127	    match media_type {
128	        "photo" => {
129	            // JPEG (FF D8 FF), PNG (89 50 4E 47), WebP (RIFF...WEBP), BMP (42 4D)
130	            data.starts_with(&[0xFF, 0xD8, 0xFF])
131	                || data.starts_with(&[0x89, 0x50, 0x4E, 0x47])
132	                || (data.len() >= 12 && &data[..4] == b"RIFF" && &data[8..12] == b"WEBP")
133	                || data.starts_with(&[0x42, 0x4D])
134	        }
135	        "video" => {
136	            // MP4/MOV (ftyp box), AVI (RIFF...AVI), WebM/MKV (1A 45 DF A3)
137	            (data.len() >= 8 && &data[4..8] == b"ftyp")
138	                || (data.len() >= 12 && &data[..4] == b"RIFF" && &data[8..12] == b"AVI ")
139	                || data.starts_with(&[0x1A, 0x45, 0xDF, 0xA3])
140	        }
141	        "audio" => {
142	            // MP3 (FF FB / FF F3 / ID3), WAV (RIFF...WAVE), FLAC (fLaC), OGG (OggS), AAC (FF F1)
143	            data.starts_with(&[0xFF, 0xFB])
144	                || data.starts_with(&[0xFF, 0xF3])
145	                || data.starts_with(b"ID3")
146	                || (data.len() >= 12 && &data[..4] == b"RIFF" && &data[8..12] == b"WAVE")
147	                || data.starts_with(b"fLaC")
148	                || data.starts_with(b"OggS")
149	                || data.starts_with(&[0xFF, 0xF1])
150	        }
151	        _ => false,
152	    }
153	}
