155	// POST /media/upload/chunk — receive and persist chunk data
156	pub async fn upload_chunk(
157	    State(state): State<AppState>,
158	    Extension(tid): Extension<TraceId>,
159	    Extension(user): Extension<SessionUser>,
160	    Json(body): Json<UploadChunkRequest>,
161	) -> Result<Json<serde_json::Value>, AppError> {
162	    let t = &tid.0;
163	    require_write_role(&user, t)?;
164	
165	    let session: Option<(String, String, i64, String)> = sqlx::query_as(
166	        "SELECT received_chunks, status, total_chunks, media_type FROM upload_sessions WHERE id = ? AND uploader_id = ?"
167	    ).bind(&body.upload_id).bind(&user.user_id)
168	        .fetch_optional(&state.db).await
169	        .map_err(db_err(t))?;
170	
171	    let (received_json, status, total, media_type) = session.ok_or_else(|| AppError::not_found("Upload session not found", t))?;
172	    if status != "in_progress" {
173	        return Err(AppError::conflict("Upload already complete or failed", t));
174	    }
175	    if body.chunk_index < 0 || body.chunk_index >= total {
176	        return Err(AppError::validation("chunk_index out of range", t));
177	    }
178	
179	    // Decode base64 chunk data (if provided)
180	    let chunk_bytes = if !body.data.is_empty() {
181	        use base64::Engine;
182	        base64::engine::general_purpose::STANDARD
183	            .decode(&body.data)
184	            .map_err(|_| AppError::validation("Invalid base64 chunk data", t))?
185	    } else {
186	        Vec::new()
187	    };
188	
189	    // Validate format on first chunk (chunk_index == 0) using magic bytes
190	    if body.chunk_index == 0 && !chunk_bytes.is_empty() {
191	        if !validate_media_format(&media_type, &chunk_bytes) {
192	            return Err(AppError::validation(
193	                format!("File content does not match declared media_type '{}'", media_type), t,
194	            ));
195	        }
196	    }
197	
198	    // Persist chunk to storage/uploads/<upload_id>/chunk_<index>
199	    if !chunk_bytes.is_empty() {
200	        let chunk_dir = format!("{}/uploads/{}", state.config.storage_dir, body.upload_id);
201	        std::fs::create_dir_all(&chunk_dir)
202	            .map_err(|e| {
203	                tracing::error!(trace_id = %t, error = %e, "Failed to create chunk dir");
204	                AppError::internal("Storage error", t)
205	            })?;
206	        let chunk_path = format!("{}/chunk_{}", chunk_dir, body.chunk_index);
207	        std::fs::write(&chunk_path, &chunk_bytes)
208	            .map_err(|e| {
209	                tracing::error!(trace_id = %t, error = %e, "Failed to write chunk");
210	                AppError::internal("Storage error", t)
211	            })?;
212	    }
213	
214	    let mut received: Vec<i64> = serde_json::from_str(&received_json).unwrap_or_default();
215	    if !received.contains(&body.chunk_index) {
216	        received.push(body.chunk_index);
217	        received.sort();
218	    }
219	    let new_json = serde_json::to_string(&received).unwrap();
220	    sqlx::query("UPDATE upload_sessions SET received_chunks = ? WHERE id = ?")
221	        .bind(&new_json).bind(&body.upload_id)
222	        .execute(&state.db).await
223	        .map_err(db_err(t))?;
224	
225	    Ok(Json(serde_json::json!({
226	        "received_count": received.len(),
227	        "total_chunks": total,
228	        "complete": received.len() as i64 == total
229	    })))
230	}
