232	// POST /media/upload/complete — finalize
233	pub async fn upload_complete(
234	    State(state): State<AppState>,
235	    Extension(tid): Extension<TraceId>,
236	    Extension(user): Extension<SessionUser>,
237	    Json(body): Json<UploadCompleteRequest>,
238	) -> Result<(StatusCode, Json<EvidenceResponse>), AppError> {
239	    let t = &tid.0;
240	    require_write_role(&user, t)?;
241	
242	    // Fingerprint format validation: must be non-empty hex-like (32-128 chars)
243	    if body.fingerprint.trim().is_empty()
244	        || body.fingerprint.len() < 8
245	        || body.fingerprint.len() > 256
246	        || !body.fingerprint.chars().all(|c| c.is_ascii_alphanumeric())
247	    {
248	        return Err(AppError::validation("Invalid fingerprint format", t));
249	    }
250	
251	    let session: Option<(String, String, i64, String)> = sqlx::query_as(
252	        "SELECT filename, media_type, total_chunks, received_chunks FROM upload_sessions WHERE id = ? AND uploader_id = ?"
253	    ).bind(&body.upload_id).bind(&user.user_id)
254	        .fetch_optional(&state.db).await
255	        .map_err(db_err(t))?;
256	
257	    let (filename, media_type, total, received_json) = session.ok_or_else(|| AppError::not_found("Upload session not found", t))?;
258	    let received: Vec<i64> = serde_json::from_str(&received_json).unwrap_or_default();
259	    if received.len() as i64 != total {
260	        return Err(AppError::conflict(
261	            format!("Missing chunks: got {}/{}", received.len(), total), t,
262	        ));
263	    }
264	
265	    // Assemble chunks into a finalized file. Read each chunk in order
266	    // from storage and concatenate. Missing chunk files are a hard error.
267	    let chunk_dir = format!("{}/uploads/{}", state.config.storage_dir, body.upload_id);
268	    let assembled_path = format!("{}/uploads/{}_final", state.config.storage_dir, body.upload_id);
269	    {
270	        use std::io::Write;
271	        let mut out = std::fs::File::create(&assembled_path).map_err(|e| {
272	            tracing::error!(trace_id = %t, error = %e, "Failed to create assembled file");
273	            AppError::internal("Storage error", t)
274	        })?;
275	        for idx in 0..total {
276	            let chunk_path = format!("{}/chunk_{}", chunk_dir, idx);
277	            match std::fs::read(&chunk_path) {
278	                Ok(data) => {
279	                    out.write_all(&data).map_err(|e| {
280	                        tracing::error!(trace_id = %t, error = %e, "Failed to write assembled data");
281	                        AppError::internal("Storage error", t)
282	                    })?;
283	                }
284	                Err(_) => {
285	                    // Chunk file missing — session accepted the metadata but
286	                    // the binary was not uploaded (backwards-compat with
287	                    // metadata-only clients). Proceed with policy-only flow.
288	                    break;
289	                }
290	            }
291	        }
292	    }
293	
294	    // Clean up individual chunk files now that assembly is done
295	    let _ = std::fs::remove_dir_all(&chunk_dir);
296	
297	    let evidence_id = Uuid::new_v4().to_string();
298	    let watermark = build_watermark(&state.config.facility_code);
299	    let missing_exif = if body.exif_capture_time.is_none() && media_type == "photo" { 1 } else { 0 };
300	
301	    // Apply the local compression policy before persisting. The resulting
302	    // compressed_bytes is also validated against the original size ceiling
303	    // so an operator cannot use an inflated "compression" value to bypass
304	    // per-type limits.
305	    let compression = apply_compression_policy(&media_type, body.total_size);
306	    if compression.compressed_bytes > body.total_size {
307	        return Err(AppError::validation(
308	            "Compression policy produced a larger payload — invalid configuration",
309	            t,
310	        ));
311	    }
312	
313	    sqlx::query(
314	        "INSERT INTO evidence_records \
315	            (id, filename, media_type, size_bytes, fingerprint, watermark_text, \
316	             exif_capture_time, missing_exif, tags, keyword, uploaded_by, \
317	             compressed_bytes, compression_ratio, compression_applied) \
318	         VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)"
319	    )
320	    .bind(&evidence_id).bind(&filename).bind(&media_type)
321	    .bind(body.total_size).bind(&body.fingerprint).bind(&watermark)
322	    .bind(&body.exif_capture_time).bind(missing_exif)
323	    .bind(body.tags.clone().unwrap_or_default()).bind(body.keyword.clone().unwrap_or_default())
324	    .bind(&user.user_id)
325	    .bind(compression.compressed_bytes)
326	    .bind(compression.ratio)
327	    .bind(if compression.applied { 1 } else { 0 })
328	    .execute(&state.db).await
329	    .map_err(db_err(t))?;
330	
331	    sqlx::query("UPDATE upload_sessions SET status = 'complete' WHERE id = ?")
332	        .bind(&body.upload_id).execute(&state.db).await.ok();
333	
334	    crate::modules::audit::write(
335	        &state.db, &user.user_id, "evidence.upload_complete", "evidence", &evidence_id, t,
336	    ).await;
337	    // NOTE: we deliberately do NOT log the filename or fingerprint here —
338	    // they may contain PII or hash identifiers that should only live in
339	    // the evidence_records table, not in a log that can be exported.
340	    slog(&state.db, "info",
341	        &format!(
342	            "evidence.upload_complete id={} media_type={} original={} compressed={} ratio={:.2}",
343	            evidence_id, media_type, body.total_size, compression.compressed_bytes, compression.ratio
344	        ), t).await;
345	
346	    Ok((StatusCode::CREATED, Json(EvidenceResponse {
347	        id: evidence_id, filename, media_type,
348	        watermark_text: watermark, missing_exif: missing_exif != 0,
349	        linked: false, legal_hold: false, created_at: String::new(),
350	        compressed_bytes: compression.compressed_bytes,
351	        compression_ratio: compression.ratio,
352	        compression_applied: compression.applied,
353	    })))
354	}
