356	// GET /evidence?keyword=&tag=&from=&to= — list with search filters
357	pub async fn list(
358	    State(state): State<AppState>,
359	    Extension(tid): Extension<TraceId>,
360	    Query(q): Query<HashMap<String, String>>,
361	) -> Result<Json<Vec<EvidenceResponse>>, AppError> {
362	    let t = &tid.0;
363	
364	    let mut sql = String::from(
365	        "SELECT id, filename, media_type, watermark_text, missing_exif, linked, legal_hold, created_at, \
366	                size_bytes, compressed_bytes, compression_ratio, compression_applied \
367	         FROM evidence_records WHERE 1=1"
368	    );
369	    let mut binds: Vec<String> = Vec::new();
370	
371	    if let Some(k) = q.get("keyword") {
372	        if !k.is_empty() {
373	            sql.push_str(" AND (keyword LIKE ? OR filename LIKE ?)");
374	            binds.push(format!("%{}%", k));
375	            binds.push(format!("%{}%", k));
376	        }
377	    }
378	    if let Some(tag) = q.get("tag") {
379	        if !tag.is_empty() {
380	            sql.push_str(" AND tags LIKE ?");
381	            binds.push(format!("%{}%", tag));
382	        }
383	    }
384	    if let Some(from) = q.get("from") {
385	        if !from.is_empty() {
386	            sql.push_str(" AND (exif_capture_time >= ? OR created_at >= ?)");
387	            binds.push(from.clone());
388	            binds.push(from.clone());
389	        }
390	    }
391	    if let Some(to) = q.get("to") {
392	        if !to.is_empty() {
393	            sql.push_str(" AND (exif_capture_time <= ? OR created_at <= ?)");
394	            binds.push(to.clone());
395	            binds.push(to.clone());
396	        }
397	    }
398	    sql.push_str(" ORDER BY created_at DESC");
399	
400	    let mut query = sqlx::query_as::<_, EvidenceRow>(&sql);
401	    for b in &binds { query = query.bind(b); }
402	    let rows = query.fetch_all(&state.db).await.map_err(db_err(t))?;
403	
404	    Ok(Json(rows.into_iter().map(|r| {
405	        // Older rows (pre-migration) may not have compression metadata set.
406	        // Fall back to the original size so the response shape is stable.
407	        let compressed_bytes = r.compressed_bytes.unwrap_or(r.size_bytes);
408	        let ratio = r.compression_ratio.unwrap_or(1.0);
409	        EvidenceResponse {
410	            id: r.id, filename: r.filename, media_type: r.media_type,
411	            watermark_text: r.watermark_text, missing_exif: r.missing_exif != 0,
412	            linked: r.linked != 0, legal_hold: r.legal_hold != 0,
413	            created_at: r.created_at,
414	            compressed_bytes,
415	            compression_ratio: ratio,
416	            compression_applied: r.compression_applied != 0,
417	        }
418	    }).collect()))
419	}
